-- Corrected import script based on User Feedback
BEGIN;

-- 1. Update Bins (Active bins on site)
ON CONFLICT (bin_number) DO UPDATE SET size = EXCLUDED.size, status = EXCLUDED.status, current_address = EXCLUDED.current_address, last_moved_at = EXCLUDED.last_moved_at, notes = EXCLUDED.notes;

-- 2. Update Orders (Delivered or Pending)
ON CONFLICT (order_number, type) DO UPDATE SET bin_size = EXCLUDED.bin_size, bin_type = EXCLUDED.bin_type, service_date = EXCLUDED.service_date, address = EXCLUDED.address, status = EXCLUDED.status, updated_at = now();

COMMIT;
